---
/**
 * SidebarGroup.astro -- astro-shad sidebar section. Converted from
 * shadcn's SidebarGroup + SidebarGroupLabel + SidebarGroupContent, folded
 * into one file (label as a prop, content as the default slot) -- the
 * three-way split existed in React only to let SidebarGroupLabel render
 * as something other than a div (`useRender`); this registry drops that
 * polymorphism (not needed by any known consumer yet).
 *
 * `SidebarMenu`/`SidebarMenuItem`'s `<ul>/<li>` wrapper is also dropped --
 * `SidebarMenuButton`s are placed directly as children, one per row.
 *
 *   <SidebarGroup label="Platform">
 *     <SidebarMenuButton href="/create" active>Create</SidebarMenuButton>
 *     <SidebarMenuButton href="/docs">Docs</SidebarMenuButton>
 *   </SidebarGroup>
 */
import { cn } from '../../lib/utils';

interface Props {
  label?: string;
  class?: string;
  [key: string]: unknown;
}

const { label, class: className, ...rest } = Astro.props;
---

<div class={cn('flex w-full min-w-0 flex-col gap-1 p-2', className)} {...rest}>
  {label && (
    <div class="flex h-8 shrink-0 items-center rounded-md px-2 text-xs font-medium text-sidebar-foreground/70 transition-opacity duration-200 group-data-[state=collapsed]/sidebar:opacity-0">
      {label}
    </div>
  )}
  <div class="flex w-full min-w-0 flex-col gap-0.5">
    <slot />
  </div>
</div>

---
/**
 * SidebarMenuButton.astro -- astro-shad sidebar nav row. Converted from
 * shadcn's SidebarMenuButton (`useRender` polymorphism + `cva` variants +
 * a `useSidebar()` read for the collapsed-state tooltip). Polymorphism ->
 * `href` prop (renders `<a>`, else `<button>`, same rule as Button.astro);
 * `cva` variants dropped to the single default look (shadcn's `outline`
 * variant wasn't used anywhere upstream -- add back as a `variant` prop
 * if a design needs it); the icon-mode width collapse reads the ancestor
 * `<Sidebar>`'s `data-state` via `group-data-[state=collapsed]/sidebar:*`
 * instead of context.
 *
 * `tooltip` wraps the button in `Tooltip.astro` -- shown on hover always
 * (a small divergence from shadcn, which hides it except when the
 * sidebar is collapsed; not worth the extra plumbing for a registry
 * primitive, and a tooltip on an already-labelled expanded row is
 * harmless).
 *
 *   <SidebarMenuButton href="/create" active>
 *     <Icon slot="icon" name="lucide:layout-grid" />Create
 *   </SidebarMenuButton>
 *   <SidebarMenuButton tooltip="Settings"><Icon slot="icon" name="lucide:settings" />Settings</SidebarMenuButton>
 */
import { cn } from '../../lib/utils';
import Tooltip from './Tooltip.astro';

interface Props {
  href?: string;
  active?: boolean;
  disabled?: boolean;
  tooltip?: string;
  class?: string;
  [key: string]: unknown;
}

const {
  href,
  active = false,
  disabled,
  tooltip,
  class: className,
  ...rest
} = Astro.props;

const classes = cn(
  'flex h-8 w-full items-center gap-2 overflow-hidden rounded-md p-2 text-left text-sm outline-none transition-colors ' +
    'hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sidebar-ring ' +
    'disabled:pointer-events-none disabled:opacity-50 aria-disabled:pointer-events-none aria-disabled:opacity-50 ' +
    'data-active:bg-sidebar-accent data-active:font-medium data-active:text-sidebar-accent-foreground ' +
    'group-data-[state=collapsed]/sidebar:size-8 group-data-[state=collapsed]/sidebar:justify-center group-data-[state=collapsed]/sidebar:p-0 ' +
    '[&_svg]:size-4 [&_svg]:shrink-0',
  className
);
---

{tooltip ? (
  <Tooltip content={tooltip} side="right" class="w-full">
    {href ? (
      <a href={href} data-active={active ? '' : undefined} aria-disabled={disabled} class={classes} {...rest}>
        <slot name="icon" /><span class="truncate group-data-[state=collapsed]/sidebar:hidden"><slot /></span>
      </a>
    ) : (
      <button type="button" data-active={active ? '' : undefined} disabled={disabled} class={classes} {...rest}>
        <slot name="icon" /><span class="truncate group-data-[state=collapsed]/sidebar:hidden"><slot /></span>
      </button>
    )}
  </Tooltip>
) : href ? (
  <a href={href} data-active={active ? '' : undefined} aria-disabled={disabled} class={classes} {...rest}>
    <slot name="icon" /><span class="truncate group-data-[state=collapsed]/sidebar:hidden"><slot /></span>
  </a>
) : (
  <button type="button" data-active={active ? '' : undefined} disabled={disabled} class={classes} {...rest}>
    <slot name="icon" /><span class="truncate group-data-[state=collapsed]/sidebar:hidden"><slot /></span>
  </button>
)}

---
/**
 * SidebarTrigger.astro -- astro-shad sidebar toggle button. Converted from
 * shadcn's SidebarTrigger (a Button wrapping `useSidebar().toggleSidebar`).
 * No context to call: `<Sidebar>` and `<SidebarInset>` are SIBLINGS in
 * consumer markup (`<div class="flex min-h-svh"><Sidebar/><SidebarInset>
 * <SidebarTrigger/>...`), and this button typically lives inside
 * SidebarInset -- so `[data-astro-shad-sidebar-root]` (Sidebar's own
 * wrapper) is never an ANCESTOR of the trigger, only a sibling's
 * descendant. The click handler therefore walks UP from the trigger
 * through each ancestor, searching that ancestor's subtree for the
 * sidebar root, until it finds the nearest shared wrapper -- effectively
 * "the closest ancestor whose subtree contains a sidebar", which is
 * exactly the consumer's own flex wrapper, no extra markup required from
 * them. From there: flip the desktop `<Sidebar>`'s `data-state`, and
 * click() the mobile `<Sheet>`'s trigger span so Sheet's own open logic
 * runs -- one button drives both render branches (see Sidebar.astro's
 * header comment). The keyboard shortcut (cmd/ctrl+b in the shadcn
 * source) is dropped -- global key bindings are a page-level decision,
 * not a primitive's to own.
 *
 *   <SidebarTrigger />
 */
import { cn } from '../../lib/utils';

interface Props {
  class?: string;
  [key: string]: unknown;
}

const { class: className, ...rest } = Astro.props;
---

<button
  type="button"
  data-sidebar-trigger
  aria-label="Toggle Sidebar"
  class={cn(
    'grid size-8 shrink-0 place-items-center rounded-md text-foreground/70 transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
    className
  )}
  {...rest}
>
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <rect width="18" height="18" x="3" y="3" rx="2" /><path d="M9 3v18" />
  </svg>
  <span class="sr-only">Toggle Sidebar</span>
</button>

<script>
  function findSidebarRoot(trigger: HTMLElement): HTMLElement | null {
    /* trigger.closest() only searches ancestors -- the sidebar root is a
       sibling's descendant, not an ancestor, so walk up manually and
       search each ancestor's subtree instead. */
    let node = trigger.parentElement;
    while (node) {
      const root = node.querySelector<HTMLElement>('[data-astro-shad-sidebar-root]');
      if (root) return root;
      node = node.parentElement;
    }
    return null;
  }

  document.addEventListener('click', (e) => {
    const t = e.target as HTMLElement;
    const trigger = t.closest?.('[data-sidebar-trigger]');
    if (!trigger) return;

    const root = findSidebarRoot(trigger as HTMLElement);
    if (!root) return;

    const aside = root.querySelector<HTMLElement>('[data-astro-shad-sidebar]');
    if (aside) {
      aside.dataset.state = aside.dataset.state === 'collapsed' ? 'expanded' : 'collapsed';
      /* Root also carries data-state (for SidebarInset's peer-data-[state=
         collapsed] inset-variant margin) -- keep both in sync. */
      root.dataset.state = aside.dataset.state;
    }
    root.querySelector<HTMLElement>('[data-sheet-trigger]')?.click();
  });
</script>
